sys_script_include.script:
var BaseParser = Class.create();
BaseParser.prototype = {
    table_name: "",

    /**
     * Push a reference into this object based on @value
     */
    getMatches: function(e) {
        var gr_table = new GlideRecord(this.table_name);

        // if @value matches exactly one name
        var refs = this.getExactMatches(gr_table, e);
        if (refs) {
            return refs;
        }

        // if @value matches the start of exactly one name
        refs = this.getLeadingMatches(gr_table, e);
        if (refs) {
            return refs;
        }

        // if @value is found somewhere in exactly one name
        refs = this.getPartialMatches(gr_table, e);
        if (refs) {
            return refs;
        }

        return null;
    },

    getExactMatches: function(gr, e, limit = 2) {
        return this.getMatchesByOperator(gr, e, "=", limit);
    },

    getLeadingMatches: function(gr, e, limit = 2) {
        return this.getMatchesByOperator(gr, e, "STARTSWITH", limit);
    },

    getPartialMatches: function(gr, e, limit = 2) {
        return this.getMatchesByOperator(gr, e, "CONTAINS", limit);
    },

    getMatchesByOperator: function(gr, e, operator, limit = 2) {
        var refs = [];
        gr.initialize();
        var qc = gr.addQuery("name", operator, e.value);
        qc.addOrCondition("display_name", operator, e.value);
        gr.setLimit(limit);
        gr.query();
        while (gr.hasNext()) {
            gr.next();
            refs.push({
                "sys_id": gr.getValue("sys_id"),
                "name": gr.getValue("name") || ""
            });
        }
        return refs;
    },

    DEFAULT_HELPER: function(grattachment, fields = ["key", "value"], filter = BaseParser.FILTER.ALL) {
        var objects = [];
        var parser = new sn_impex.GlideExcelParser();
        var attachment = new GlideSysAttachment();
        var attachmentStream = attachment.getContentStream(grattachment.sys_id);
        parser.parse(attachmentStream);

        while (parser.next()) {
            var rowCount = 0;
            var row = parser.getRow();

            // break when all requested columns are empty
            var doBreak = true;
            fields.forEach(function(f) {
                if (!gs.nil(row[f])) doBreak = false;
            });
            if (doBreak) {
                break;
            }

            var object = {};
            fields.forEach(function(f) {
                object[f] = row[f] || "";
            });
            objects.push(object);

        }

        return objects;
    },

    Filter: {
        ALL: 0,
        VALID: 1,
        INVALID: 2
    },

    initialize: function() {},

    validate: function(refs) {
        var result = {
            "valid": true,
            "message": ""
        };

        if (refs.length == 0) {
            result.valid = false;
            result.message = "No matches on " + this.table_name;
        }

        if (refs.length > 1) {
            result.valid = false;
            result.message = "Ambiguous, >1 matches on " + this.table_name;
        }

        return result;
    },

    getEntries: function(gr, helper, filter = this.Filter.ALL) {
        var objects = helper(gr, ["key", "value"], filter);
        var i = 0;
        for (i = 0; i < objects.length; i++) {
            var obj = objects[i];
            var refs = this.getMatches(obj);
            var validationResult = this.validate(refs);
            obj.valid = validationResult.valid;
            obj.message = validationResult.message;
            obj["refs"] = refs;
        }

        if (filter == this.Filter.VALID) objects = objects.filter(function(e) {
            return e.valid == true;
        });
        if (filter == this.Filter.INVALID) objects = objects.filter(function(e) {
            return e.valid == false;
        });

        return objects;
    },

    getMap: function(gr, helper, filter = this.Filter.ALL) {
        var entries = this.getEntries(gr, helper, filter);
        return entries.reduce((acc, item) => {
            acc[item.key] = {
				"value": item.value,
                "valid": item.valid,
                "message": item.message
            };
            return acc;
        }, {});
    },

    type: 'BaseParser'
};
